/**
 * Obter capítulo do banco de dados offline
 */
export function obterCapituloOffline(livro: string, capitulo: number): string | null {
  const livroData = BIBLIA_COMPLETA_NAA[livro];
  if (!livroData) return null;
  
  const texto = livroData[capitulo];
  return texto || null;
}

/**
 * Verificar se capítulo existe no banco de dados
 */
export function capituloExiste(livro: string, capitulo: number): boolean {
  const livroData = BIBLIA_COMPLETA_NAA[livro];
  if (!livroData) return false;
  return capitulo in livroData;
}

/**
 * Obter lista de livros disponíveis
 */
export function obterLivrosDisponiveis(): string[] {
  return Object.keys(BIBLIA_COMPLETA_NAA);
}
